CREATE OR REPLACE FUNCTION pass_contract_fts_rank(search_vector tsvector, query text)
RETURNS real AS $$
    SELECT coalesce(ts_rank(search_vector, dcpass_fts_query(query)), 0);
$$ LANGUAGE sql IMMUTABLE;

